use std::io::{self, Write};

struct Job {
    name: String,
    command: String,
}

fn main() -> io::Result<()> {
    let mut jobs = Vec::new();
    println!("Enter job names and commands (e.g., Name: Setup, Command: cargo build). Type 'END' on a new line when finished.");

    loop {
        print!("Job Input > ");
        io::stdout().flush()?;
        let mut line = String::new();
        match io::stdin().read_line(&mut line)? {
            0 => break,
            _ => {
                let trimmed = line.trim();
                if trimmed == "END" {
                    break;
                }
                let name_result = if let Some(name) = trimmed.split(", Name:")
                    .collect::<Vec<&str>>()
                    .get(0)
                {
                    Some(name.split(" \"\"\": ").next().unwrap_or(&"").trim_matches('"').to_string())
                } else {
                    None
                };

                let command_result = if let Some(command) = trimmed.split(", Command:")
                    .collect::<Vec<&str>>()
                    .get(0)
                {
                    Some(command.split(" \"\"\": ").next().unwrap_or(&"").trim_matches('"').to_string())
                } else {
                    None
                };

                if let (Some(name), Some(command)) = (name_result, command_result) {
                    if !name.is_empty() && !command.is_empty() {
                        jobs.push(Job { name, command });
                    }
                }
            }
        }
    }

    for job in jobs {
        print!("n--- Running Job: {} ---n", job.name);
        println!("Executing: {}", job.command);
        if job.command.contains("fail") {
            eprint!("Job {} failed during execution.n", job.name);
            return Ok(());
        }
        println!("Job {} finished successfully.n", job.name);
    }

    Ok(())
}

use std::io::{self, BufReader, BufWriter, Write, BufRead};
use std::error::Error;
use std::fmt;

struct DataRecord {
    id: u32,
    name: String,
}

impl fmt::Display for DataRecord {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "ID: {}, Name: {}", self.id, self.name)
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let stdin = io::stdin();
    let mut reader = BufReader::new(stdin.lock());
    let stdout = io::stdout();
    let mut writer = BufWriter::new(stdout.lock());

    let mut buffer = String::new();
    loop {
        print!("Enter data line or press Ctrl+D to finish: ");
        io::stdout().flush()?;

        match reader.read_line(&mut buffer) {
            Ok(0) => break,
            Ok(_) => {
                let trimmed = buffer.trim();
                if trimmed.is_empty() {
                    buffer.clear();
                    continue;
                }

                let parts: Vec<&str> = trimmed.split(',').collect();
                if parts.len() == 2 {
                    match parts[0].parse::<u32>() {
                        Ok(id) => {
                            let record = DataRecord {
                                id,
                                name: parts[1].to_string(),
                            };
                            println!("Processed internal object: {}", record);
                            writeln!(writer, "RESULT|{}", record)?;
                        }
                        Err(_) => println!("Skipping line due to bad ID format."),
                    }
                } else {
                    println!("Skipping line: expected two comma-separated values.");
                }
                buffer.clear();
            },
            Err(e) => {
                eprintln!("Error reading from stdin: {}", e);
                break;
            }
        }
    }

    writer.flush()?;
    Ok(())
}

