    let file = File::open(file_path)?;
    let mut reader = BufReader::new(file);

    const READ_CHUNK_SIZE: usize = 4096;
    let mut buffer = [0u8; READ_CHUNK_SIZE];
    let mut total_bytes_read: u64 = 0;

    loop {
        match reader.read(&mut buffer) {
            Ok(0) => break,
            Ok(n) => {
                total_bytes_read += n as u64;
                let chunk = &buffer[..n];
                println!("Successfully read {} bytes for this segment.", n);
            }
            Err(e) => return Err(e),
        }
    }

    println!("nAnalysis complete. Total bytes processed: {}", total_bytes_read);
    Ok(())
}

use std::fs::{File, OpenOptions};
use std::io::{self, BufRead, Write, Seek};
use std::path::Path;
use std::thread;
use std::time::Duration;
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct LogState {
    handles: HashMap<String, File>,
    positions: Arc<Mutex<HashMap<String, u64>>>,
}

impl LogState {
    fn new(files: &[String]) -> io::Result<Self> {
        let mut handles = HashMap::new();
        let mut positions = HashMap::new();
        for file_path in files {
            let path = Path::new(file_path);
            let file = OpenOptions::new().read(true).append(false).open(path)?;
            handles.insert(file_path.clone(), file);
            positions.insert(file_path.clone(), 0);
        }
        Ok(LogState {
            handles: handles,
            positions: Arc::new(Mutex::new(positions)),
        })
    }

    fn read_new_logs(&mut self) -> io::Result<Vec<String>> {
        let mut new_lines = Vec::new();
        let mut current_positions = self.positions.lock().unwrap();

        for (file_name, _) in self.handles.iter() {
            let start_pos = *current_positions.get(file_name).unwrap_or(&0);
            let path = Path::new(file_name);
            let mut temp_file = File::options().read(true).open(path)?;
            temp_file.seek(io::SeekFrom::Start(start_pos))?;

            let mut reader = io::BufReader::new(&mut temp_file);
            let mut buffer = String::new();
            let mut found_data = false;

            loop {
                buffer.clear();
                match reader.read_line(&mut buffer) {
                    Ok(0) => break,
                    Ok(_) => {
                        found_data = true;
                        new_lines.push(buffer.trim().to_string());
                        let new_size = reader.stream_position()? + buffer.len() as u64 - 1;
                        *current_positions.get_mut(file_name).unwrap() = new_size;
                    }
                    Err(e) => return Err(e),
                }
            }
        }
        Ok(new_lines)
    }
}

fn main() -> io::Result<()> {
    let files_to_tail = vec!["log1.txt".to_string(), "log2.txt".to_string()];
    let mut state = LogState::new(&files_to_tail)?;

    println!("Starting log aggregator. Press Ctrl+C to exit.");

    loop {
        thread::sleep(Duration::from_secs(1));
        match state.read_new_logs() {
            Ok(lines) => {
                if !lines.is_empty() {
                    for line in lines {
                        println!("-> LOG RECEIVED: {}", line);
                    }
                } else {
                    print!(".");
                    io::stdout().flush()?;
                }
            }
            Err(e) => {
                eprintln!("Error reading logs: {}", e);
                break;
            }
        }
    }
    Ok(())
}

use std::io::{self, BufReader, BufRead};
use std::fs::File;

fn main() -> io::Result<()> {
    let filename = String::from("game_events.txt");
    let file = File::open(&filename).expect("Failed to open file");
    let reader = BufReader::new(file);

    for line in reader.lines() {
        let line_content = line?;
        println!("Processing event: {}", line_content);
        if line_content.contains("TERMINATE") {
            break;
        }
    }

    Ok(())
}
